theme.css:
#title-card{gap:24px !important;}#title-card-subtitle{display:flex;flex-direction:column;align-items:center;gap:16px;color:#f3ead8;}#title-card-subtitle img{display:block;height:auto;max-width:640px;width:640px;}#title-card-subtitle div.deck-subtitle{max-width:1500px;line-height:1.45;font-size:36px;color:#d9c9ad;}#title-card-subtitle .deck-subtitle-note{display:block;max-width:1300px;line-height:1.35;font-size:28px;color:#b29b7a;}

#root.theme-rose-pine-moon #title-card-rule,
#root.theme-rose-pine-moon #narrative-rule,
#root.theme-rose-pine-moon .slidey-bar-fill,
#root.theme-rose-pine-moon .spinner-bar,
#root.theme-rose-pine-moon #stat-value,
#root.theme-rose-pine-moon #trace-title,
#root.theme-rose-pine-moon #book-title,
#root.theme-rose-pine-moon #diagramsvg-title,
#root.theme-rose-pine-moon #diagram-title,
#root.theme-rose-pine-moon #narrative-eyebrow,
#root.theme-rose-pine-moon #thread-title,
#root.theme-rose-pine-moon #diagramsvg-panel-label,
#root.theme-rose-pine-moon .cards-title,
#root.theme-rose-pine-moon .image-title,
#root.theme-rose-pine-moon .imagecompare-title,
#root.theme-rose-pine-moon .mermaid-title,
#root.theme-rose-pine-moon .table-title,
#root.theme-rose-pine-moon .code-call,
#root.theme-rose-pine-moon .code-dot-call,
#root.theme-rose-pine-moon .table-crown,
#root.theme-rose-pine-moon .table-row-hi,
#root.theme-rose-pine-moon a {
  color: var(--slidey-gold);
}

#root.theme-rose-pine-moon #title-card-rule,
#root.theme-rose-pine-moon #narrative-rule,
#root.theme-rose-pine-moon .slidey-bar-fill,
#root.theme-rose-pine-moon .code-line-hl,
#root.theme-rose-pine-moon #stat-value,
#root.theme-rose-pine-moon .dsvg-arrow path,
#root.theme-rose-pine-moon .dsvg-edge path,
#root.theme-rose-pine-moon .dsvg-edge line {
  border-color: var(--slidey-rose);
  color: var(--slidey-gold);
}

#root.theme-rose-pine-moon #title-card-rule,
#root.theme-rose-pine-moon #narrative-rule,
#root.theme-rose-pine-moon .slidey-bar-fill,
#root.theme-rose-pine-moon #stat-value {
  background: linear-gradient(90deg, var(--slidey-gold), var(--slidey-rose));
}

#root.theme-rose-pine-moon .dsvg-edge line:not(.dsvg-gate-bar),
#root.theme-rose-pine-moon .dsvg-edge path,
#root.theme-rose-pine-moon .dsvg-arrow path,
#root.theme-rose-pine-moon .dsvg-arrow-back path,
#root.theme-rose-pine-moon .dsvg-edge-back path,
#root.theme-rose-pine-moon .dsvg-edge-gate.dsvg-gate-oracle,
#root.theme-rose-pine-moon .dsvg-gate-bar.dsvg-gate-oracle,
#root.theme-rose-pine-moon .dsvg-edge-recycle,
#root.theme-rose-pine-moon .dsvg-arrow-recycle path {
  stroke: var(--slidey-gold);
  fill: var(--slidey-gold);
}

#root.theme-rose-pine-moon .dsvg-arrow-back path,
#root.theme-rose-pine-moon .dsvg-edge-back path {
  stroke: var(--slidey-highlight-high);
  fill: var(--slidey-background);
}

#root.theme-rose-pine-moon .dsvg-edge-recycle path {
  fill: var(--slidey-background) !important;
  stroke: var(--slidey-background) !important;
}

#root.theme-rose-pine-moon .dsvg-arrow-recycle path {
  fill: var(--slidey-background) !important;
  stroke: var(--slidey-background) !important;
}

#root.theme-rose-pine-moon .dsvg-node.dsvg-style-primary rect,
#root.theme-rose-pine-moon .dsvg-node.dsvg-style-secondary rect,
#root.theme-rose-pine-moon .dsvg-node rect {
  stroke: var(--slidey-rose);
}

#root.theme-rose-pine-moon .dsvg-node.dsvg-style-primary rect {
  fill: var(--slidey-highlight-muted);
}

#root.theme-rose-pine-moon .dsvg-node.dsvg-style-secondary rect {
  fill: var(--slidey-highlight-low);
}

#root.theme-rose-pine-moon .dsvg-node.dsvg-style-primary .dsvg-label,
#root.theme-rose-pine-moon .dsvg-node.dsvg-style-secondary .dsvg-label {
  fill: var(--slidey-gold);
}

#root.theme-rose-pine-moon .dsvg-node.dsvg-style-primary .dsvg-sub,
#root.theme-rose-pine-moon .dsvg-node.dsvg-style-secondary .dsvg-sub,
#root.theme-rose-pine-moon .dsvg-node.dsvg-style-primary .dsvg-line,
#root.theme-rose-pine-moon .dsvg-node.dsvg-style-secondary .dsvg-line {
  fill: var(--slidey-text);
}

#root.theme-rose-pine-moon .trace-turn-user::before,
#root.theme-rose-pine-moon .thread-system.thread-system-jira,
#root.theme-rose-pine-moon .thread-system.thread-system-bitbucket {
  color: var(--slidey-gold);
}

#root.theme-rose-pine-moon .json-key,
#root.theme-rose-pine-moon .code-key,
#root.theme-rose-pine-moon .cards-bullet,
#root.theme-rose-pine-moon .cards-card.cards-style-primary,
#root.theme-rose-pine-moon .cards-col.accent-blue,
#root.theme-rose-pine-moon .cards-col.accent-purple,
#root.theme-rose-pine-moon .cards-qa-question,
#root.theme-rose-pine-moon .cards-qa-answer,
#root.theme-rose-pine-moon .mockup-blue,
#root.theme-rose-pine-moon .tx-hud-app,
#root.theme-rose-pine-moon .tx-card-turn {
  color: var(--slidey-gold);
  border-color: var(--slidey-rose);
}


#root.theme-rose-pine-moon #table-title,
#root.theme-rose-pine-moon [id$="-title"],
#root.theme-rose-pine-moon #cta-wordmark,
#root.theme-rose-pine-moon #cta-tagline,
#root.theme-rose-pine-moon #cta-url {
  color: var(--slidey-gold);
}

#root.theme-rose-pine-moon #cta-wordmark {
  background: linear-gradient(180deg, var(--slidey-gold), var(--slidey-rose));
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent !important;
}

#root.theme-rose-pine-moon #cta-url {
  background: var(--slidey-overlay);
  border-color: var(--slidey-highlight-high);
}

#root.theme-rose-pine-moon .spinner-bar,
#root.theme-rose-pine-moon #spinner-bar {
  background: linear-gradient(90deg, var(--slidey-gold), var(--slidey-rose)) !important;
}

#book-region .book-takeaway {
  font-size: 24px;
  line-height: 1.35;
}

#book-region .book-count-1 .book-takeaway {
  font-size: 32px;
  line-height: 1.3;
}

#book-region .book-caption {
  font-size: 32px;
  line-height: 1.4;
  max-width: 1500px;
}

#narrative-region {
  max-width: 1600px;
}

#narrative-body {
  font-size: 68px;
  line-height: 1.18;
  max-width: 1380px;
}

#narrative-lede {
  font-size: 36px;
  line-height: 1.42;
  max-width: 1360px;
}
